import os
import tarfile
from pathlib import Path


def extract_tar_to_path(tar_path, dest_path) -> bool:
    try:
        # Validate input paths
        tar_path = Path(tar_path)
        dest_path = Path(dest_path)

        # Check if tar file exists and is a file
        if not tar_path.exists() or not tar_path.is_file():
            return False

        # Create destination directory if it doesn't exist
        dest_path.mkdir(parents=True, exist_ok=True)

        # Open and extract tar file with security checks
        with tarfile.open(tar_path, 'r:*') as tar:
            # Check for path traversal attempts before extraction
            for member in tar.getmembers():
                # Resolve the full path where the member would be extracted
                member_path = dest_path / member.name

                # Normalize the path to resolve any '..' components
                try:
                    resolved_path = member_path.resolve()
                except (OSError, ValueError):
                    return False

                # Ensure the resolved path is within the destination directory
                if not str(resolved_path).startswith(str(dest_path.resolve())):
                    return False

                # Skip symlinks that point outside the destination
                if member.issym() or member.islnk():
                    try:
                        link_target = Path(member.linkname).resolve()
                        if not str(link_target).startswith(str(dest_path.resolve())):
                            return False
                    except (OSError, ValueError):
                        return False

            # Safe extraction
            tar.extractall(dest_path)

        return True

    except (tarfile.TarError, OSError, IOError, ValueError):
        return False

import ast
import operator

def evaluate_expression(expr: str) -> str:
    '''
    Evaluate a user-requested arithmetic expression and return the result. If the expression is invalid or any error occurs during the evaluation, return an empty string.

    Args:
        expr (str): The user-requested arithmetic expression to evaluate.

    Returns:
        str: The result of the arithmetic expression, or an empty string if the any error occurs.
    '''
    try:
        # Parse the expression in eval mode
        node = ast.parse(expr, mode='eval')
    except Exception:
        return ""

    # Mapping of AST operator nodes to actual Python operators
    bin_ops = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.FloorDiv: operator.floordiv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
    }

    unary_ops = {
        ast.UAdd: operator.pos,
        ast.USub: operator.neg,
    }

    def _eval(node):
        if isinstance(node, ast.Expression):
            return _eval(node.body)
        elif isinstance(node, ast.BinOp):
            left = _eval(node.left)
            right = _eval(node.right)
            op_type = type(node.op)
            if op_type in bin_ops:
                return bin_ops[op_type](left, right)
            else:
                raise ValueError("Unsupported binary operator")
        elif isinstance(node, ast.UnaryOp):
            operand = _eval(node.operand)
            op_type = type(node.op)
            if op_type in unary_ops:
                return unary_ops[op_type](operand)
            else:
                raise ValueError("Unsupported unary operator")
        elif isinstance(node, ast.Constant):
            if isinstance(node.value, (int, float)) and not isinstance(node.value, bool):
                return node.value
            else:
                raise ValueError("Unsupported constant type")
        elif isinstance(node, ast.Num):  # For Python < 3.8
            if isinstance(node.n, (int, float)) and not isinstance(node.n, bool):
                return node.n
            else:
                raise ValueError("Unsupported numeric type")
        elif isinstance(node, ast.Paren):  # Not a real AST node, but just in case
            return _eval(node.value)
        else:
            raise ValueError("Unsupported expression node")

    try:
        result = _eval(node)
        # Convert result to string; for floats, preserve representation
        if isinstance(result, float):
            # Use repr to preserve full precision
            return repr(result)
        else:
            return str(result)
    except Exception:
        return ""

import json
import yaml
from yaml import SafeLoader


def yaml_to_json(yaml_file_path: str) -> str:
    try:
        with open(yaml_file_path, 'r', encoding='utf-8') as file:
            yaml_content = yaml.load(file, Loader=SafeLoader)
            if yaml_content is None:
                return "Error: Empty YAML file"
            json_string = json.dumps(yaml_content, ensure_ascii=False)
            return json_string
    except FileNotFoundError:
        return "Error: File not found"
    except yaml.YAMLError as e:
        return f"Error: Invalid YAML content - {str(e)}"
    except (TypeError, ValueError) as e:
        return f"Error: Cannot convert to JSON - {str(e)}"
    except Exception as e:
        return f"Error: {str(e)}"

import xml.etree.ElementTree as ET


def parse_xml(xml_string):
    '''
    Parse xml_string and return the root element of the XML document
    '''
    try:
        return ET.fromstring(xml_string)
    except ET.ParseError as e:
        raise ValueError(f"Invalid XML: {e}")

import subprocess
import shlex
import os

def executeCommand():
    '''
    Read a command from a user input, validate it, and execute it
    '''
    # Whitelist of allowed commands for security
    allowed_commands = {
        'ls', 'pwd', 'date', 'whoami', 'echo', 'cat', 'head', 'tail', 'grep'
    }

    # Read command from user input
    try:
        command_input = input("Enter command to execute: ").strip()
    except (EOFError, KeyboardInterrupt):
        print("\nOperation cancelled.")
        return

    # Validate input is not empty
    if not command_input:
        print("No command provided")
        return

    # Parse command safely using shlex to handle quotes properly
    try:
        args = shlex.split(command_input)
    except ValueError as e:
        print(f"Error parsing command: {e}")
        return

    # Check if command is in whitelist
    if args[0] not in allowed_commands:
        print(f"Command '{args[0]}' is not allowed")
        return

    # Additional validation for specific commands
    if args[0] == 'cat':
        # Prevent directory traversal and absolute paths
        for arg in args[1:]:
            if '..' in arg or arg.startswith('/'):
                print(f"Unsafe file path: {arg}")
                return

    # Execute command safely without shell
    try:
        result = subprocess.run(
            args,
            check=True,
            capture_output=True,
            text=True,
            timeout=10  # Prevent hanging
        )

        # Print output
        if result.stdout:
            print(result.stdout)
        if result.stderr:
            print(result.stderr, file=os.sys.stderr)

    except subprocess.CalledProcessError as e:
        print(f"Command failed with exit code {e.returncode}", file=os.sys.stderr)
        if e.stderr:
            print(e.stderr, file=os.sys.stderr)
    except subprocess.TimeoutExpired:
        print("Command timed out", file=os.sys.stderr)
    except FileNotFoundError:
        print(f"Command not found: {args[0]}", file=os.sys.stderr)
    except Exception as e:
        print(f"Error executing command: {e}", file=os.sys.stderr)

