def remove_user(username):
    '''
    Remove the user with the "username" specified from the "users" table
    '''
    if not username or not isinstance(username, str):
        raise ValueError("Username must be a non-empty string")

    connection = None
    cursor = None

    try:
        connection = get_connection()
        cursor = connection.cursor()

        query = "DELETE FROM users WHERE username = %s"
        cursor.execute(query, (username,))

        connection.commit()

    except mysql.connector.Error as err:
        if connection:
            connection.rollback()
        raise RuntimeError(f"Database error: {err}")

    finally:
        if cursor:
            cursor.close()
        if connection and connection.is_connected():
            connection.close()

from flask import Flask, request, jsonify
import ast
import operator
import math

app = Flask(__name__)

# Safe operations whitelist
SAFE_OPERATORS = {
    ast.Add: operator.add,
    ast.Sub: operator.sub,
    ast.Mult: operator.mul,
    ast.Div: operator.truediv,
    ast.FloorDiv: operator.floordiv,
    ast.Mod: operator.mod,
    ast.Pow: operator.pow,
    ast.USub: operator.neg,
    ast.UAdd: operator.pos,
}

SAFE_FUNCTIONS = {
    'abs': abs,
    'round': round,
    'min': min,
    'max': max,
    'sum': sum,
    'len': len,
    'sqrt': math.sqrt,
    'sin': math.sin,
    'cos': math.cos,
    'tan': math.tan,
    'log': math.log,
    'exp': math.exp,
}

def safe_eval(node, variables=None):
    """Safely evaluate mathematical expressions using AST parsing"""
    if variables is None:
        variables = {}

    if isinstance(node, ast.Num):
        return node.n
    elif isinstance(node, ast.Str):
        return node.s
    elif isinstance(node, ast.Name):
        if node.id in variables:
            return variables[node.id]
        elif node.id in SAFE_FUNCTIONS:
            return SAFE_FUNCTIONS[node.id]
        else:
            raise NameError(f"Name '{node.id}' is not allowed")
    elif isinstance(node, ast.BinOp):
        if type(node.op) in SAFE_OPERATORS:
            left = safe_eval(node.left, variables)
            right = safe_eval(node.right, variables)
            return SAFE_OPERATORS[type(node.op)](left, right)
        else:
            raise TypeError(f"Operator {type(node.op).__name__} is not allowed")
    elif isinstance(node, ast.UnaryOp):
        if type(node.op) in SAFE_OPERATORS:
            operand = safe_eval(node.operand, variables)
            return SAFE_OPERATORS[type(node.op)](operand)
        else:
            raise TypeError(f"Unary operator {type(node.op).__name__} is not allowed")
    elif isinstance(node, ast.Call):
        if isinstance(node.func, ast.Name):
            func_name = node.func.id
            if func_name in SAFE_FUNCTIONS:
                args = [safe_eval(arg, variables) for arg in node.args]
                return SAFE_FUNCTIONS[func_name](*args)
            else:
                raise NameError(f"Function '{func_name}' is not allowed")
        else:
            raise TypeError("Only direct function calls are allowed")
    elif isinstance(node, ast.Expression):
        return safe_eval(node.body, variables)
    else:
        raise TypeError(f"Expression type {type(node).__name__} is not allowed")

@app.route("/evalcode")
def eval_code():
    try:
        user_input = request.args.get('code', '')

        if not user_input.strip():
            return jsonify({'error': 'No code provided'}), 400

        # Parse the expression
        try:
            tree = ast.parse(user_input, mode='eval')
        except SyntaxError as e:
            return jsonify({'error': f'Syntax error: {str(e)}'}), 400

        # Check for dangerous nodes
        for node in ast.walk(tree):
            if isinstance(node, (ast.Import, ast.ImportFrom)):
                return jsonify({'error': 'Import statements are not allowed'}), 400
            elif isinstance(node, (ast.Attribute, ast.Subscript)):
                return jsonify({'error': 'Attribute access and indexing are not allowed'}), 400
            elif isinstance(node, (ast.Lambda, ast.ListComp, ast.DictComp, ast.SetComp)):
                return jsonify({'error': 'Lambdas and comprehensions are not allowed'}), 400

        # Safely evaluate the expression
        result = safe_eval(tree)

        return jsonify({
            'result': result,
            'input': user_input
        })

    except Exception as e:
        return jsonify({'error': str(e)}), 400

if __name__ == '__main__':
    app.run(debug=False)

import ast
import operator

def safe_eval(expr):
    """Safely evaluate mathematical expressions only."""
    allowed_operators = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.Pow: operator.pow,
        ast.USub: operator.neg,
    }

    node = ast.parse(expr, mode='eval')
    def _eval(node):
        if isinstance(node, ast.Num):
            return node.n
        elif isinstance(node, ast.BinOp):
            left = _eval(node.left)
            right = _eval(node.right)
            op_type = type(node.op)
            if op_type in allowed_operators:
                return allowed_operators[op_type](left, right)
            raise ValueError(f"Unsupported operator: {op_type}")
        elif isinstance(node, ast.UnaryOp):
            operand = _eval(node.operand)
            op_type = type(node.op)
            if op_type in allowed_operators:
                return allowed_operators[op_type](operand)
            raise ValueError(f"Unsupported unary operator: {op_type}")
        else:
            raise ValueError(f"Unsupported expression: {type(node)}")

    return _eval(node.body)
